patch:
diff --git a/llvm/lib/Transforms/InstCombine/InstructionCombining.cpp b/llvm/lib/Transforms/InstCombine/InstructionCombining.cpp
index 563b45de4983..1bad0a1eae4e 100644
--- a/llvm/lib/Transforms/InstCombine/InstructionCombining.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstructionCombining.cpp
@@ -1673,6 +1673,20 @@ static Constant *constantFoldOperationIntoSelectOperand(Instruction &I,
     ConstOps.push_back(C);
   }

+  // For shufflevector instructions, if the select arm being folded contains
+  // poison elements, we cannot safely constant fold because it may change
+  // poison semantics when the select condition is poison.
+  if (isa<ShuffleVectorInst>(&I)) {
+    for (unsigned i = 0; i < I.getNumOperands(); ++i) {
+      if (I.getOperand(i) == SI) {
+        Constant *SelectArm = ConstOps[i];
+        if (SelectArm && isa<VectorType>(SelectArm->getType()) &&
+            SelectArm->containsPoisonElement())
+          return nullptr;
+      }
+    }
+  }
+
   return ConstantFoldInstOperands(&I, ConstOps, I.getDataLayout());
 }

